from typing import List

def solve(words: List[str]) -> List[int]:
    n = len(words)
    if n <= 1:
        return [0] * n

    answer = []

    for i in range(n):
        temp_words = words[:i] + words[i+1:]
        max_len = 0

        for j in range(len(temp_words) - 1):
            s1 = temp_words[j]
            s2 = temp_words[j+1]
            current_len = 0
            min_len = min(len(s1), len(s2))

            for k in range(min_len):
                if s1[k] == s2[k]:
                    current_len += 1
                else:
                    break

            if current_len > max_len:
                max_len = current_len

        answer.append(max_len)

    return answer
